/*==============================================================*/
/* Table: CATPRI                                                */
/*==============================================================*/
CREATE TABLE CATPRI
(
    ID_CATPRI_CODE       VARCHAR(4) NOT NULL,
    CATPRI_NAME          VARCHAR(32) NOT NULL,
    CATPRI_TYPE          VARCHAR(4) NOT NULL,
    CATPRI_ICON          VARCHAR(32) NOT NULL,
    CATPRI_COLOR         VARCHAR(32),
    CATPRI_INDEX         INT NOT NULL,
    CATPRI_VALID_FROM    TIMESTAMP,
    CATPRI_VALID_TO      TIMESTAMP NULL,
    CATPRI_CREATED_BY    VARCHAR(16),
    CATPRI_UPDATED_BY    VARCHAR(16),
    CATPRI_CREATED_AT    TIMESTAMP,
    CATPRI_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CATPRI_CODE)
);

ALTER TABLE CATPRI COMMENT 'CATALOGO PRIORIDAD';

/*==============================================================*/
/* Import: CATPRI Catalogo de prioridad                         */
