/*==============================================================*/
/* Table: COTORD                                                */
/*==============================================================*/
CREATE TABLE COTORD
(
    ID_COTORD_CODE       INT NOT NULL AUTO_INCREMENT,
    XID_CATPRI_CODE      VARCHAR(4) NOT NULL,
    XID_COT_ID_COTORD_CODE INT,
    XID_CATPROY_CODE     INT NOT NULL,
    XID_CATCLI_CODE      INT NOT NULL,
    XID_CATSTATUS_CODE   VARCHAR(4) NOT NULL,
    COTORD_CODE          VARCHAR(8) NOT NULL,
    COTORD_PRODUCT_CODE  VARCHAR(128) NOT NULL,
    COTORD_NAME          VARCHAR(128) NOT NULL,
    COTORD_QUANTITY      INT NOT NULL,
    COTORD_ORDERED_AT    TIMESTAMP NOT NULL,
    COTORD_LOTE          VARCHAR(16),
    COTORD_ESTIMATED_DELIVERED_AT TIMESTAMP,
    COTORD_CLIENT_ORDER_CODE VARCHAR(64),
    COTORD_OBSERVATION   VARCHAR(256),
    COTORD_COMPLETED_AT  TIMESTAMP NULL,
    COTORD_CANCELED_AT   TIMESTAMP NULL,
    COTORD_PRODUCTION_STARTED_AT TIMESTAMP NULL,
    COTORD_CANCELLATION_REASON VARCHAR(256),
    COTORD_LAST_MODIFICATION_AT TIMESTAMP NOT NULL,
    COTORD_VALID_FROM    TIMESTAMP,
    COTORD_VALID_TO      TIMESTAMP NULL,
    COTORD_CREATED_BY    VARCHAR(16),
    COTORD_UPDATED_BY    VARCHAR(16),
    COTORD_CREATED_AT    TIMESTAMP,
    COTORD_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_COTORD_CODE)
);

ALTER TABLE COTORD COMMENT 'PEDIDOS';

ALTER TABLE COTORD ADD CONSTRAINT XID_COTORD_CODE_XID_CATCLI_CODE FOREIGN KEY (XID_CATCLI_CODE)
    REFERENCES CATCLI (ID_CATCLI_CODE) ON DELETE RESTRICT;

ALTER TABLE COTORD ADD CONSTRAINT XID_COTORD_CODE_XID_CATPRI_CODE FOREIGN KEY (XID_CATPRI_CODE)
    REFERENCES CATPRI (ID_CATPRI_CODE) ON DELETE RESTRICT;

ALTER TABLE COTORD ADD CONSTRAINT XID_COTORD_CODE_XID_CATPROY_CODE FOREIGN KEY (XID_CATPROY_CODE)
    REFERENCES CATPROY (ID_CATPROY_CODE) ON DELETE RESTRICT;

ALTER TABLE COTORD ADD CONSTRAINT XID_COTORD_CODE_XID_CATSTATUS_CODE FOREIGN KEY (XID_CATSTATUS_CODE)
    REFERENCES CATSTATUS (ID_CATSTATUS_CODE) ON DELETE RESTRICT;

ALTER TABLE COTORD ADD CONSTRAINT XID_COTORD_CODE_XID_COTORD_CODE FOREIGN KEY (XID_COT_ID_COTORD_CODE)
    REFERENCES COTORD (ID_COTORD_CODE) ON DELETE RESTRICT;

